import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,d as p}from"./app-45b6ee47.js";const e="/assets/5JnFDa-7016a1ad.gif",t="/assets/oYmyOi-66616fb2.gif",o="/assets/b3bHTW-39a47d8b.gif",c="/assets/2q3wKr-fe3d30f3.gif",l="/assets/PJvr5A-31c2bf91.jpg",i={},u=p(`<p>经典排序算法在面试中占有很大的比重，也是基础，为了未雨绸缪，整理并用Python实现了七大经典排序算法，包括冒泡排序，插入排序，选择排序，希尔排序，归并排序，快速排序，堆排序。之所以用Python实现，主要是因为它更接近伪代码，能用更少的代码实现算法，更利于理解。</p><p>本篇博客所有排序实现均默认从小到大。</p><h2 id="冒泡排序-bubblesort" tabindex="-1"><a class="header-anchor" href="#冒泡排序-bubblesort" aria-hidden="true">#</a> 冒泡排序 <code>BubbleSort</code></h2><h3 id="介绍" tabindex="-1"><a class="header-anchor" href="#介绍" aria-hidden="true">#</a> 介绍</h3><p>冒泡排序的原理非常简单，它重复地走访过要排序的数列，一次比较两个元素，如果他们的顺序逆序就把他们交换过来。</p><h3 id="步骤" tabindex="-1"><a class="header-anchor" href="#步骤" aria-hidden="true">#</a> 步骤</h3><ol><li>比较相邻的元素。如果第一个比第二个大，就交换他们两个。</li><li>对第0个到第n-1个数据做同样的工作。这时，最大的数就“浮”到了数组最后的位置上。</li><li>针对所有的元素重复以上的步骤，除了最后一个。</li><li>持续每次对越来越少的元素重复上面的步骤，直到没有任何一对数字需要比较。</li></ol><p>不过针对上述实现过程还有两种优化方案。</p><ul><li>优化1：某一趟遍历如果没有数据交换，则说明已经排好序了，因此不用再进行迭代了。用一个标记记录这个状态即可。</li><li>优化2：记录某次遍历时最后发生数据交换的位置，这个位置之后的数据显然已经有序，不用再排序了。因此通过记录最后发生数据交换的位置就可以确定下次循环的范围了。</li></ul><h3 id="源代码" tabindex="-1"><a class="header-anchor" href="#源代码" aria-hidden="true">#</a> 源代码</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">bubble_sort</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token punctuation">:</span>
    n <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span>                   <span class="token comment">#获得数组的长度</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">for</span> j <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span>n<span class="token operator">-</span>i<span class="token punctuation">)</span><span class="token punctuation">:</span>
            <span class="token keyword">if</span>  ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">&gt;</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token punctuation">:</span>       <span class="token comment">#如果前者比后者大</span>
                ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span>       <span class="token comment">#则交换两者</span>
    <span class="token keyword">return</span> ary


<span class="token comment">#优化1：某一趟遍历如果没有数据交换，则说明已经排好序了，因此不用再进行迭代了。</span>
<span class="token comment">#用一个标记记录这个状态即可。</span>
<span class="token keyword">def</span> <span class="token function">bubble_sort2</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token punctuation">:</span>
    n <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span>
        flag <span class="token operator">=</span> <span class="token number">1</span>                    <span class="token comment">#标记</span>
        <span class="token keyword">for</span> j <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span>n<span class="token operator">-</span>i<span class="token punctuation">)</span><span class="token punctuation">:</span>
            <span class="token keyword">if</span>  ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">&gt;</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token punctuation">:</span>
                ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span>
                flag <span class="token operator">=</span> <span class="token number">0</span>
        <span class="token keyword">if</span> flag <span class="token punctuation">:</span>                   <span class="token comment">#全排好序了，直接跳出</span>
            <span class="token keyword">break</span>
    <span class="token keyword">return</span> ary

<span class="token comment">#优化2：记录某次遍历时最后发生数据交换的位置，这个位置之后的数据显然已经有序了。</span>
<span class="token comment"># 因此通过记录最后发生数据交换的位置就可以确定下次循环的范围了。</span>
<span class="token keyword">def</span> <span class="token function">bubble_sort3</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token punctuation">:</span>
    n <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span>
    k <span class="token operator">=</span> n                           <span class="token comment">#k为循环的范围，初始值n</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span>
        flag <span class="token operator">=</span> <span class="token number">1</span>
        <span class="token keyword">for</span> j <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span>k<span class="token punctuation">)</span><span class="token punctuation">:</span>        <span class="token comment">#只遍历到最后交换的位置即可</span>
            <span class="token keyword">if</span>  ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">&gt;</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token punctuation">:</span>
                ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>j<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span>
                k <span class="token operator">=</span> j               <span class="token comment">#记录最后交换的位置</span>
                flag <span class="token operator">=</span> <span class="token number">0</span>
        <span class="token keyword">if</span> flag <span class="token punctuation">:</span>
            <span class="token keyword">break</span>
    <span class="token keyword">return</span> ary
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="选择排序-selectionsort" tabindex="-1"><a class="header-anchor" href="#选择排序-selectionsort" aria-hidden="true">#</a> 选择排序 <code>SelectionSort</code></h2><h3 id="介绍-1" tabindex="-1"><a class="header-anchor" href="#介绍-1" aria-hidden="true">#</a> 介绍</h3><p>选择排序无疑是最简单直观的排序。它的工作原理如下。</p><h3 id="步骤-1" tabindex="-1"><a class="header-anchor" href="#步骤-1" aria-hidden="true">#</a> 步骤</h3><ol><li>在未排序序列中找到最小（大）元素，存放到排序序列的起始位置。</li><li>再从剩余未排序元素中继续寻找最小（大）元素，然后放到已排序序列的末尾。</li><li>以此类推，直到所有元素均排序完毕。</li></ol><h3 id="源代码-1" tabindex="-1"><a class="header-anchor" href="#源代码-1" aria-hidden="true">#</a> 源代码</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">select_sort</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token punctuation">:</span>
    n <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token builtin">min</span> <span class="token operator">=</span> i                             <span class="token comment">#最小元素下标标记</span>
        <span class="token keyword">for</span> j <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>i<span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">,</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span>
            <span class="token keyword">if</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">&lt;</span> ary<span class="token punctuation">[</span><span class="token builtin">min</span><span class="token punctuation">]</span> <span class="token punctuation">:</span>
                <span class="token builtin">min</span> <span class="token operator">=</span> j                     <span class="token comment">#找到最小值的下标</span>
        ary<span class="token punctuation">[</span><span class="token builtin">min</span><span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>i<span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span><span class="token builtin">min</span><span class="token punctuation">]</span>   <span class="token comment">#交换两者</span>
    <span class="token keyword">return</span> ary
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="插入排序-insertionsort" tabindex="-1"><a class="header-anchor" href="#插入排序-insertionsort" aria-hidden="true">#</a> 插入排序 <code>InsertionSort</code></h2><h3 id="介绍-2" tabindex="-1"><a class="header-anchor" href="#介绍-2" aria-hidden="true">#</a> 介绍</h3><p>插入排序的工作原理是，对于每个未排序数据，在已排序序列中从后向前扫描，找到相应位置并插入。</p><h3 id="步骤-2" tabindex="-1"><a class="header-anchor" href="#步骤-2" aria-hidden="true">#</a> 步骤</h3><ol><li>从第一个元素开始，该元素可以认为已经被排序</li><li>取出下一个元素，在已经排序的元素序列中从后向前扫描</li><li>如果被扫描的元素（已排序）大于新元素，将该元素后移一位</li><li>重复步骤3，直到找到已排序的元素小于或者等于新元素的位置</li><li>将新元素插入到该位置后</li><li>重复步骤2~5</li></ol><h3 id="排序演示" tabindex="-1"><a class="header-anchor" href="#排序演示" aria-hidden="true">#</a> 排序演示</h3><figure><img src="`+e+`" alt="5JnFDa" tabindex="0" loading="lazy"><figcaption>5JnFDa</figcaption></figure><h3 id="源代码-2" tabindex="-1"><a class="header-anchor" href="#源代码-2" aria-hidden="true">#</a> 源代码</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">insert_sort</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token punctuation">:</span>
    n <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">if</span> ary<span class="token punctuation">[</span>i<span class="token punctuation">]</span> <span class="token operator">&lt;</span> ary<span class="token punctuation">[</span>i<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">:</span>
            temp <span class="token operator">=</span> ary<span class="token punctuation">[</span>i<span class="token punctuation">]</span>
            index <span class="token operator">=</span> i           <span class="token comment">#待插入的下标</span>
            <span class="token keyword">for</span> j <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>i<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">:</span>  <span class="token comment">#从i-1 循环到 0 (包括0)</span>
                <span class="token keyword">if</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">&gt;</span> temp <span class="token punctuation">:</span>
                    ary<span class="token punctuation">[</span>j<span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span>
                    index <span class="token operator">=</span> j   <span class="token comment">#记录待插入下标</span>
                <span class="token keyword">else</span> <span class="token punctuation">:</span>
                    <span class="token keyword">break</span>
            ary<span class="token punctuation">[</span>index<span class="token punctuation">]</span> <span class="token operator">=</span> temp
    <span class="token keyword">return</span> ary
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="希尔排序-shellsort" tabindex="-1"><a class="header-anchor" href="#希尔排序-shellsort" aria-hidden="true">#</a> 希尔排序 <code>ShellSort</code></h2><h3 id="介绍-3" tabindex="-1"><a class="header-anchor" href="#介绍-3" aria-hidden="true">#</a> 介绍：</h3><p>希尔排序，也称递减增量排序算法，实质是分组插入排序。由 Donald Shell 于1959年提出。希尔排序是非稳定排序算法。</p><h3 id="步骤-3" tabindex="-1"><a class="header-anchor" href="#步骤-3" aria-hidden="true">#</a> 步骤：</h3><p>希尔排序的基本思想是：将数组列在一个表中并对列分别进行插入排序，重复这过程，不过每次用更长的列（步长更长了，列数更少了）来进行。最后整个表就只有一列了。将数组转换至表是为了更好地理解这算法，算法本身还是使用数组进行排序。</p><ol><li>例如，假设有这样一组数<code>[ 13 14 94 33 82 25 59 94 65 23 45 27 73 25 39 10 ]</code>，如果我们以步长为5开始进行排序，我们可以通过将这列表放在有5列的表中来更好地描述算法，这样他们就应该看起来是这样：<div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>13 14 94 33 82
25 59 94 65 23
45 27 73 25 39
10
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li>然后我们对每列进行排序：<div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>10 14 73 25 23
13 27 94 33 39
25 59 94 65 82
45
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li>将上述四行数字，依序接在一起时我们得到：<code>[ 10 14 73 25 23 13 27 94 33 39 25 59 94 65 82 45 ]</code>。这时10已经移至正确位置了，然后再以3为步长进行排序：<div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>10 14 73
25 23 13
27 94 33
39 25 59
94 65 82
45
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>排序之后变为：<div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>10 14 13
25 23 33
27 25 59
39 65 73
45 94 82
94
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li>最后以1步长进行排序（此时就是简单的插入排序了）。</li></ol><h3 id="源代码-3" tabindex="-1"><a class="header-anchor" href="#源代码-3" aria-hidden="true">#</a> 源代码</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">shell_sort</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token punctuation">:</span>
    n <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span>
    gap <span class="token operator">=</span> <span class="token builtin">round</span><span class="token punctuation">(</span>n<span class="token operator">/</span><span class="token number">2</span><span class="token punctuation">)</span>       <span class="token comment">#初始步长 , 用round四舍五入取整</span>
    <span class="token keyword">while</span> gap <span class="token operator">&gt;</span> <span class="token number">0</span> <span class="token punctuation">:</span>
        <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>gap<span class="token punctuation">,</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span>        <span class="token comment">#每一列进行插入排序 , 从gap 到 n-1</span>
            temp <span class="token operator">=</span> ary<span class="token punctuation">[</span>i<span class="token punctuation">]</span>
            j <span class="token operator">=</span> i
            <span class="token keyword">while</span> <span class="token punctuation">(</span> j <span class="token operator">&gt;=</span> gap <span class="token keyword">and</span> ary<span class="token punctuation">[</span>j<span class="token operator">-</span>gap<span class="token punctuation">]</span> <span class="token operator">&gt;</span> temp <span class="token punctuation">)</span><span class="token punctuation">:</span>    <span class="token comment">#插入排序</span>
                ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>j<span class="token operator">-</span>gap<span class="token punctuation">]</span>
                j <span class="token operator">=</span> j <span class="token operator">-</span> gap
            ary<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">=</span> temp
        gap <span class="token operator">=</span> <span class="token builtin">round</span><span class="token punctuation">(</span>gap<span class="token operator">/</span><span class="token number">2</span><span class="token punctuation">)</span>                     <span class="token comment">#重新设置步长</span>
    <span class="token keyword">return</span> ary
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="归并排序-mergesort" tabindex="-1"><a class="header-anchor" href="#归并排序-mergesort" aria-hidden="true">#</a> 归并排序 <code>MergeSort</code></h2><h3 id="介绍-4" tabindex="-1"><a class="header-anchor" href="#介绍-4" aria-hidden="true">#</a> 介绍</h3><p>归并排序是采用分治法的一个非常典型的应用。归并排序的思想就是先递归分解数组，再合并数组。</p><p>先考虑合并两个有序数组，基本思路是比较两个数组的最前面的数，谁小就先取谁，取了后相应的指针就往后移一位。然后再比较，直至一个数组为空，最后把另一个数组的剩余部分复制过来即可。</p><p>再考虑递归分解，基本思路是将数组分解成left和right，如果这两个数组内部数据是有序的，那么就可以用上面合并数组的方法将这两个数组合并排序。如何让这两个数组内部是有序的？可以再二分，直至分解出的小组只含有一个元素时为止，此时认为该小组内部已有序。然后合并排序相邻二个小组即可。</p><h3 id="排序演示-1" tabindex="-1"><a class="header-anchor" href="#排序演示-1" aria-hidden="true">#</a> 排序演示</h3><figure><img src="`+t+`" alt="oYmyOi" tabindex="0" loading="lazy"><figcaption>oYmyOi</figcaption></figure><h3 id="源代码-4" tabindex="-1"><a class="header-anchor" href="#源代码-4" aria-hidden="true">#</a> 源代码</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">merge_sort</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">if</span> <span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span> <span class="token operator">&lt;=</span> <span class="token number">1</span> <span class="token punctuation">:</span> <span class="token keyword">return</span> ary
    num <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token operator">/</span><span class="token number">2</span><span class="token punctuation">)</span>       <span class="token comment">#二分分解</span>
    left <span class="token operator">=</span> merge_sort<span class="token punctuation">(</span>ary<span class="token punctuation">[</span><span class="token punctuation">:</span>num<span class="token punctuation">]</span><span class="token punctuation">)</span>
    right <span class="token operator">=</span> merge_sort<span class="token punctuation">(</span>ary<span class="token punctuation">[</span>num<span class="token punctuation">:</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
    <span class="token keyword">return</span> merge<span class="token punctuation">(</span>left<span class="token punctuation">,</span>right<span class="token punctuation">)</span>    <span class="token comment">#合并数组</span>

<span class="token keyword">def</span> <span class="token function">merge</span><span class="token punctuation">(</span>left<span class="token punctuation">,</span>right<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token triple-quoted-string string">&#39;&#39;&#39;合并操作，
    将两个有序数组left[]和right[]合并成一个大的有序数组&#39;&#39;&#39;</span>
    l<span class="token punctuation">,</span>r <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">,</span><span class="token number">0</span>           <span class="token comment">#left与right数组的下标指针</span>
    result <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>
    <span class="token keyword">while</span> l<span class="token operator">&lt;</span><span class="token builtin">len</span><span class="token punctuation">(</span>left<span class="token punctuation">)</span> <span class="token keyword">and</span> r<span class="token operator">&lt;</span><span class="token builtin">len</span><span class="token punctuation">(</span>right<span class="token punctuation">)</span> <span class="token punctuation">:</span>
        <span class="token keyword">if</span> left<span class="token punctuation">[</span>l<span class="token punctuation">]</span> <span class="token operator">&lt;</span> right<span class="token punctuation">[</span>r<span class="token punctuation">]</span><span class="token punctuation">:</span>
            result<span class="token punctuation">.</span>append<span class="token punctuation">(</span>left<span class="token punctuation">[</span>l<span class="token punctuation">]</span><span class="token punctuation">)</span>
            l <span class="token operator">+=</span> <span class="token number">1</span>
        <span class="token keyword">else</span><span class="token punctuation">:</span>
            result<span class="token punctuation">.</span>append<span class="token punctuation">(</span>right<span class="token punctuation">[</span>r<span class="token punctuation">]</span><span class="token punctuation">)</span>
            r <span class="token operator">+=</span> <span class="token number">1</span>
    result <span class="token operator">+=</span> left<span class="token punctuation">[</span>l<span class="token punctuation">:</span><span class="token punctuation">]</span>
    result <span class="token operator">+=</span> right<span class="token punctuation">[</span>r<span class="token punctuation">:</span><span class="token punctuation">]</span>
    <span class="token keyword">return</span> result
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="快速排序-quicksort" tabindex="-1"><a class="header-anchor" href="#快速排序-quicksort" aria-hidden="true">#</a> 快速排序 <code>QuickSort</code></h2><h3 id="介绍-5" tabindex="-1"><a class="header-anchor" href="#介绍-5" aria-hidden="true">#</a> 介绍</h3><p>快速排序通常明显比同为<code>Ο(n log n)</code>的其他算法更快，因此常被采用，而且快排采用了分治法的思想，所以在很多笔试面试中能经常看到快排的影子。可见掌握快排的重要性。</p><h3 id="步骤-4" tabindex="-1"><a class="header-anchor" href="#步骤-4" aria-hidden="true">#</a> 步骤</h3><ol><li>从数列中挑出一个元素作为基准数。</li><li>分区过程，将比基准数大的放到右边，小于或等于它的数都放到左边。</li><li>再对左右区间递归执行第二步，直至各区间只有一个数。</li></ol><h3 id="排序演示-2" tabindex="-1"><a class="header-anchor" href="#排序演示-2" aria-hidden="true">#</a> 排序演示</h3><figure><img src="`+o+`" alt="b3bHTW" tabindex="0" loading="lazy"><figcaption>b3bHTW</figcaption></figure><h3 id="源代码-5" tabindex="-1"><a class="header-anchor" href="#源代码-5" aria-hidden="true">#</a> 源代码</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">quick_sort</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">return</span> qsort<span class="token punctuation">(</span>ary<span class="token punctuation">,</span><span class="token number">0</span><span class="token punctuation">,</span><span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span>

<span class="token keyword">def</span> <span class="token function">qsort</span><span class="token punctuation">(</span>ary<span class="token punctuation">,</span>left<span class="token punctuation">,</span>right<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token comment">#快排函数，ary为待排序数组，left为待排序的左边界，right为右边界</span>
    <span class="token keyword">if</span> left <span class="token operator">&gt;=</span> right <span class="token punctuation">:</span> <span class="token keyword">return</span> ary
    key <span class="token operator">=</span> ary<span class="token punctuation">[</span>left<span class="token punctuation">]</span>     <span class="token comment">#取最左边的为基准数</span>
    lp <span class="token operator">=</span> left           <span class="token comment">#左指针</span>
    rp <span class="token operator">=</span> right          <span class="token comment">#右指针</span>
    <span class="token keyword">while</span> lp <span class="token operator">&lt;</span> rp <span class="token punctuation">:</span>
        <span class="token keyword">while</span> ary<span class="token punctuation">[</span>rp<span class="token punctuation">]</span> <span class="token operator">&gt;=</span> key <span class="token keyword">and</span> lp <span class="token operator">&lt;</span> rp <span class="token punctuation">:</span>
            rp <span class="token operator">-=</span> <span class="token number">1</span>
        <span class="token keyword">while</span> ary<span class="token punctuation">[</span>lp<span class="token punctuation">]</span> <span class="token operator">&lt;=</span> key <span class="token keyword">and</span> lp <span class="token operator">&lt;</span> rp <span class="token punctuation">:</span>
            lp <span class="token operator">+=</span> <span class="token number">1</span>
        ary<span class="token punctuation">[</span>lp<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>rp<span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>rp<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>lp<span class="token punctuation">]</span>
    ary<span class="token punctuation">[</span>left<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>lp<span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>lp<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>left<span class="token punctuation">]</span>
    qsort<span class="token punctuation">(</span>ary<span class="token punctuation">,</span>left<span class="token punctuation">,</span>lp<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span>
    qsort<span class="token punctuation">(</span>ary<span class="token punctuation">,</span>rp<span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">,</span>right<span class="token punctuation">)</span>
    <span class="token keyword">return</span> ary

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="堆排序-heapsort" tabindex="-1"><a class="header-anchor" href="#堆排序-heapsort" aria-hidden="true">#</a> 堆排序 <code>HeapSort</code></h2><h3 id="介绍-6" tabindex="-1"><a class="header-anchor" href="#介绍-6" aria-hidden="true">#</a> 介绍：</h3><p>堆排序在 <code>top K</code> 问题中使用比较频繁。堆排序是采用二叉堆的数据结构来实现的，虽然实质上还是一维数组。二叉堆是一个近似完全二叉树 。</p><blockquote><p>二叉堆具有以下性质：</p></blockquote><p>父节点的键值总是大于或等于（小于或等于）任何一个子节点的键值。<br> 每个节点的左右子树都是一个二叉堆（都是最大堆或最小堆）。</p><h3 id="步骤-5" tabindex="-1"><a class="header-anchor" href="#步骤-5" aria-hidden="true">#</a> 步骤</h3><ol><li><p>构造最大堆（<code>Build_Max_Heap</code>）：若数组下标范围为<code>0~n</code>，考虑到单独一个元素是大根堆，则从下标n/2开始的元素均为大根堆。于是只要从<code>n/2-1</code>开始，向前依次构造大根堆，这样就能保证，构造到某个节点时，它的左右子树都已经是大根堆。</p></li><li><p>堆排序（<code>HeapSort</code>）：由于堆是用数组模拟的。得到一个大根堆后，数组内部并不是有序的。因此需要将堆化数组有序化。思想是移除根节点，并做最大堆调整的递归运算。第一次将<code>heap[0]</code>与<code>heap[n-1]</code>交换，再对<code>heap[0...n-2]</code>做最大堆调整。第二次将<code>heap[0]</code>与<code>heap[n-2]</code>交换，再对<code>heap[0...n-3]</code>做最大堆调整。重复该操作直至<code>heap[0]</code>和<code>heap[1]</code>交换。由于每次都是将最大的数并入到后面的有序区间，故操作完后整个数组就是有序的了。</p></li><li><p>最大堆调整（<code>Max_Heapify</code>）：该方法是提供给上述两个过程调用的。目的是将堆的末端子节点作调整，使得子节点永远小于父节点 。</p></li></ol><h3 id="排序演示-3" tabindex="-1"><a class="header-anchor" href="#排序演示-3" aria-hidden="true">#</a> 排序演示</h3><figure><img src="`+c+`" alt="2q3wKr" tabindex="0" loading="lazy"><figcaption>2q3wKr</figcaption></figure><h3 id="源代码-6" tabindex="-1"><a class="header-anchor" href="#源代码-6" aria-hidden="true">#</a> 源代码</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">heap_sort</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span> <span class="token punctuation">:</span>
    n <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>ary<span class="token punctuation">)</span>
    first <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span>n<span class="token operator">/</span><span class="token number">2</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span>       <span class="token comment">#最后一个非叶子节点</span>
    <span class="token keyword">for</span> start <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>first<span class="token punctuation">,</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token punctuation">:</span>     <span class="token comment">#构造大根堆</span>
        max_heapify<span class="token punctuation">(</span>ary<span class="token punctuation">,</span>start<span class="token punctuation">,</span>n<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span>
    <span class="token keyword">for</span> end <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>n<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token number">0</span><span class="token punctuation">,</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">:</span>           <span class="token comment">#堆排，将大根堆转换成有序数组</span>
        ary<span class="token punctuation">[</span>end<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>end<span class="token punctuation">]</span>
        max_heapify<span class="token punctuation">(</span>ary<span class="token punctuation">,</span><span class="token number">0</span><span class="token punctuation">,</span>end<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span>
    <span class="token keyword">return</span> ary


<span class="token comment">#最大堆调整：将堆的末端子节点作调整，使得子节点永远小于父节点</span>
<span class="token comment">#start为当前需要调整最大堆的位置，end为调整边界</span>
<span class="token keyword">def</span> <span class="token function">max_heapify</span><span class="token punctuation">(</span>ary<span class="token punctuation">,</span>start<span class="token punctuation">,</span>end<span class="token punctuation">)</span><span class="token punctuation">:</span>
    root <span class="token operator">=</span> start
    <span class="token keyword">while</span> <span class="token boolean">True</span> <span class="token punctuation">:</span>
        child <span class="token operator">=</span> root<span class="token operator">*</span><span class="token number">2</span> <span class="token operator">+</span><span class="token number">1</span>               <span class="token comment">#调整节点的子节点</span>
        <span class="token keyword">if</span> child <span class="token operator">&gt;</span> end <span class="token punctuation">:</span> <span class="token keyword">break</span>
        <span class="token keyword">if</span> child<span class="token operator">+</span><span class="token number">1</span> <span class="token operator">&lt;=</span> end <span class="token keyword">and</span> ary<span class="token punctuation">[</span>child<span class="token punctuation">]</span> <span class="token operator">&lt;</span> ary<span class="token punctuation">[</span>child<span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token punctuation">:</span>
            child <span class="token operator">=</span> child<span class="token operator">+</span><span class="token number">1</span>             <span class="token comment">#取较大的子节点</span>
        <span class="token keyword">if</span> ary<span class="token punctuation">[</span>root<span class="token punctuation">]</span> <span class="token operator">&lt;</span> ary<span class="token punctuation">[</span>child<span class="token punctuation">]</span> <span class="token punctuation">:</span>     <span class="token comment">#较大的子节点成为父节点</span>
            ary<span class="token punctuation">[</span>root<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>child<span class="token punctuation">]</span> <span class="token operator">=</span> ary<span class="token punctuation">[</span>child<span class="token punctuation">]</span><span class="token punctuation">,</span>ary<span class="token punctuation">[</span>root<span class="token punctuation">]</span>     <span class="token comment">#交换</span>
            root <span class="token operator">=</span> child
        <span class="token keyword">else</span> <span class="token punctuation">:</span>
            <span class="token keyword">break</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>下面为七种经典排序算法指标对比情况：<br><img src="`+l+'" alt="PJvr5A" loading="lazy"></p>',66),r=[u];function d(k,m){return s(),a("div",null,r)}const h=n(i,[["render",d],["__file","经典排序算法.html.vue"]]);export{h as default};
